export function glassPanelSx() {
  return {
    border: '1px solid rgba(255,255,255,0.36)',
    background: 'linear-gradient(130deg, rgba(255,255,255,0.42), rgba(255,255,255,0.14))',
    backdropFilter: 'blur(16px)',
    WebkitBackdropFilter: 'blur(16px)',
    boxShadow: '0 18px 44px rgba(3, 17, 33, 0.22)',
  };
}
